function getContextualPrompt(context) {
  let contextAdditions = "";
  if (context.mode === "tactical") {
    contextAdditions += "\n[MODE: TACTICAL] Prioritize brevity and actionable intelligence.\n";
  }
  if (context.hasVisualInput) {
    contextAdditions += "\n[VISUAL INPUT ACTIVE] Camera feed available for analysis.\n";
  }
  if (context.hasAudioInput) {
    contextAdditions += "\n[AUDIO INPUT ACTIVE] Microphone feed available.\n";
  }
  if (context.hasLocation) {
    contextAdditions += "\n[LOCATION SERVICES ACTIVE] GPS and mapping available.\n";
  }
  if (context.urgencyLevel === "critical") {
    contextAdditions += "\n[URGENCY: CRITICAL] Immediate response required. Prioritize safety.\n";
  } else if (context.urgencyLevel === "high") {
    contextAdditions += "\n[URGENCY: HIGH] Swift response required.\n";
  }
  return CYRUS_SYSTEM_PROMPT + contextAdditions;
}
