    router3.get("/api/comms/news", async (req, res) => {
      try {
        let newsList = await db.select().from(newsItems).orderBy(desc8(newsItems.publishedAt)).limit(20);
        const oneHourAgo = new Date(Date.now() - 60 * 60 * 1e3);
        const isStale = newsList.length === 0 || newsList[0]?.createdAt && new Date(newsList[0].createdAt) < oneHourAgo;
        if (isStale) {
          const apiKey = process.env.NEWS_API_KEY;
          if (apiKey) {
            try {
              const topics = req.query.topics || "technology,science,world";
              const url = `https://newsapi.org/v2/top-headlines?category=technology&pageSize=20&language=en&apiKey=${apiKey}`;
              const resp = await fetch(url);
              if (resp.ok) {
                const data = await resp.json();
                const articles = data.articles || [];
                if (articles.length > 0) {
                  await db.delete(newsItems);
                  const insertValues = articles.filter((a) => a.title && a.title !== "[Removed]").map((a) => ({
                    title: a.title || "Untitled",
                    summary: a.description || a.content || "",
                    source: a.source?.name || "Unknown",
                    url: a.url || "#",
                    category: "technology",
                    publishedAt: a.publishedAt ? new Date(a.publishedAt) : /* @__PURE__ */ new Date()
                  }));
                  if (insertValues.length > 0) {
                    await db.insert(newsItems).values(insertValues);
                    newsList = await db.select().from(newsItems).orderBy(desc8(newsItems.publishedAt)).limit(20);
                  }
                }
              }
            } catch (fetchError) {
              console.error("[Comms News] Failed to fetch from NewsAPI:", fetchError);
            }
          }
        }
        const formattedNews = newsList.map((n) => ({
          id: n.id,
          title: n.title,
          summary: n.summary || "",
          source: n.source || "Unknown",
          url: n.url || "#",
          category: n.category || "general",
          publishedAt: (n.publishedAt instanceof Date ? n.publishedAt : /* @__PURE__ */ new Date()).toISOString()
        }));
        res.json(formattedNews);
      } catch (error) {
        console.error("Error fetching news:", error);
        res.status(500).json({ error: "Failed to fetch news" });
      }
    });
