function classifyQrPayload(payload) {
  try {
    const url = new URL(payload);
    const domain = url.hostname;
    const suspicious = !url.protocol.startsWith("https") || ["bit.ly", "tinyurl", "goo.gl", "t.co"].some((d) => domain.endsWith(d));
    return {
      isUrl: true,
      safe: !suspicious,
      reason: suspicious ? "Non-https or shortened domain" : "HTTPS URL",
      domain
    };
  } catch {
    const suspicious = payload.length > 512 || /token|pass|secret/i.test(payload);
    return {
      isUrl: false,
      safe: !suspicious,
      reason: suspicious ? "Contains sensitive-looking keywords" : "Plain text"
    };
  }
}
